class Solution:
  def projectDocument(self, doc: dict) -> dict:
    def recursiveProject(doc, projection, maxDepth):
      if maxDepth == 0:
        return projection
      for key, value in doc.items():
        if key.startswith('_'):
          continue
        if isinstance(value, dict):
          projection[key] = recursiveProject(value, {}, maxDepth - 1)
        else:
          projection[key] = value
      return projection
    return recursiveProject(doc, {}, doc['maxDepth'])
